/**
 * Webhook Routes
 *
 * Handles both inbound (from external providers) and outbound (to customer endpoints) webhooks.
 *
 * Inbound Routes:
 * - POST /webhooks/v1/inbound/:provider - Receive webhook from external provider
 * - GET /webhooks/v1/inbound/events - List inbound events (admin)
 * - POST /webhooks/v1/inbound/events/:id/retry - Retry failed event (admin)
 *
 * Outbound Routes:
 * - GET /webhooks/v1/endpoints - List registered endpoints
 * - POST /webhooks/v1/endpoints - Register new endpoint
 * - GET /webhooks/v1/endpoints/:id - Get endpoint details
 * - PATCH /webhooks/v1/endpoints/:id - Update endpoint
 * - DELETE /webhooks/v1/endpoints/:id - Delete endpoint
 * - GET /webhooks/v1/endpoints/:id/deliveries - List delivery attempts
 * - POST /webhooks/v1/endpoints/:id/test - Send test event
 */

import { Hono } from "hono";
import { eq, desc, and } from "drizzle-orm";
import { z } from "zod";
import type { CloudflareBindings } from "../../env";
import type { AppContext } from "../types";
import { createWebhooksDb, webhooksSchema } from "../../db";
import { getProvider, registerProvider, stripeProvider } from "./providers";
import { dispatchEvent } from "./handlers";
import { signPayload, generateWebhookSecret } from "./sign";
import { getAvailableEventTypes } from "./emit";
import { getOrgMemberRole } from "../org-access";
import { parseJsonWithSchema } from "../request-validation";

const { webhookEvents, webhookEndpoints, webhookDeliveries } = webhooksSchema;

// Register default providers
registerProvider(stripeProvider);

// Roles allowed to manage org-scoped webhook endpoints
const WEBHOOK_ADMIN_ROLES: string[] = ["owner","admin"];
const MAX_WEBHOOK_EVENTS = 100;

const endpointCreateSchema = z.object({
  url: z.string().url().max(2048),
  events: z.array(z.string().min(1).max(120)).min(1).max(MAX_WEBHOOK_EVENTS),
  name: z.string().trim().min(1).max(120).optional(),
  organizationId: z.string().min(1).max(128).optional(),
}).strict();

const endpointPatchSchema = z.object({
  url: z.string().url().max(2048).optional(),
  events: z.array(z.string().min(1).max(120)).min(1).max(MAX_WEBHOOK_EVENTS).optional(),
  name: z.union([z.string().trim().min(1).max(120), z.null()]).optional(),
  enabled: z.boolean().optional(),
}).strict().refine(
  (payload) => Object.keys(payload).length > 0,
  { message: "At least one field must be provided for update.", path: ["body"] },
);

/**
 * Webhook queue message types
 */
export interface InboundWebhookMessage {
  type: "inbound";
  eventId: string;
  provider: string;
  eventType: string;
  payload: string;
}

export interface OutboundWebhookMessage {
  type: "outbound";
  deliveryId: string;
  endpointId: string;
  eventType: string;
  payload: string;
}

export type WebhookMessage = InboundWebhookMessage | OutboundWebhookMessage;

const app = new Hono<{
  Bindings: CloudflareBindings;
  Variables: { ctx: AppContext; authDb: any; requestId: string };
}>();

// ═══════════════════════════════════════════════════════════════════
// Provider Secret Configuration
// ═══════════════════════════════════════════════════════════════════

/**
 * Get the webhook secret for a provider from environment
 */
function getProviderSecret(provider: string, env: CloudflareBindings): string | undefined {
  switch (provider) {
    case "stripe":
      return env.STRIPE_WEBHOOK_SECRET;
    default:
      return undefined;
  }
}

async function requireOrgMember(c: any, organizationId: string, requiredRoles?: string[]) {
  const ctx = c.get("ctx");
  if (ctx.userRole === "admin") {
    return { ok: true, role: "admin" as string | null };
  }
  const authDb = c.get("authDb");
  if (!authDb) {
    return { ok: false, response: c.json({ error: "Auth database unavailable" }, 500) };
  }
  const role = await getOrgMemberRole(authDb, ctx.userId, organizationId);
  if (!role) {
    return { ok: false, response: c.json({ error: "Forbidden" }, 403) };
  }
  if (requiredRoles && !requiredRoles.includes(role)) {
    return { ok: false, response: c.json({ error: "Forbidden - insufficient role" }, 403) };
  }
  return { ok: true, role };
}

/**
 * Validate a webhook URL is safe for server-side fetch (anti-SSRF)
 */
function isAllowedWebhookUrl(urlStr: string): boolean {
  try {
    const parsed = new URL(urlStr);
    // Default policy is https-only. Insecure http: is gated by the
    // `webhooks.allowInsecure` compiler config (off by default).
    if (parsed.protocol !== "https:") return false;
    const hostname = parsed.hostname.toLowerCase();
    // Block localhost and loopback
    if (hostname === "localhost" || hostname === "127.0.0.1" || hostname === "::1" || hostname === "[::1]") return false;
    // Block link-local and metadata IPs
    if (hostname === "169.254.169.254" || hostname === "metadata.google.internal") return false;
    // Block private IPv4 ranges
    const parts = hostname.split(".");
    if (parts.length === 4 && parts.every(p => /^\d+$/.test(p))) {
      const [a, b] = parts.map(Number);
      if (a === 10) return false;                          // 10.0.0.0/8
      if (a === 172 && b >= 16 && b <= 31) return false;   // 172.16.0.0/12
      if (a === 192 && b === 168) return false;             // 192.168.0.0/16
      if (a === 169 && b === 254) return false;             // 169.254.0.0/16
      if (a === 0) return false;                            // 0.0.0.0/8
    }
    // Block internal Cloudflare service hostnames
    if (hostname.endsWith(".internal") || hostname.endsWith(".local")) return false;
    return true;
  } catch {
    return false;
  }
}

async function assertEndpointAccess(c: any, endpoint: any) {
  const ctx = c.get("ctx");
  if (endpoint.organizationId) {
    const check = await requireOrgMember(c, endpoint.organizationId, WEBHOOK_ADMIN_ROLES);
    if (!check.ok) return check.response;
    return null;
  }
  if (endpoint.userId) {
    if (endpoint.userId !== ctx.userId && ctx.userRole !== "admin") {
      return c.json({ error: "Forbidden" }, 403);
    }
    return null;
  }
  // No scope at all — refuse by default. Endpoints today always have a scope
  // set on create (organizationId or userId), but a future migration that
  // dropped that invariant would otherwise fall through and silently allow.
  return c.json({ error: "Forbidden" }, 403);
}

