/**
 * POST /webhooks/v1/inbound/:provider
 *
 * Receive webhook from external provider.
 * 1. Verify signature
 * 2. Log event to database
 * 3. Queue for processing
 * 4. Return 200 immediately
 */
app.post("/inbound/:provider", async (c) => {
  const providerName = c.req.param("provider");
  const provider = getProvider(providerName);

  if (!provider) {
    return c.json({ error: `Unknown provider: ${providerName}` }, 400);
  }

  // Get the webhook secret for this provider
  const secret = getProviderSecret(providerName, c.env);
  if (!secret) {
    console.error(`Webhook secret not configured for provider: ${providerName}`);
    return c.json({ error: "Webhook not configured" }, 500);
  }

  // Get raw body and signature
  const payload = await c.req.text();
  const signature = c.req.header("stripe-signature") ||
                    c.req.header("x-webhook-signature") ||
                    c.req.header("x-hub-signature-256") ||
                    "";

  // Verify signature
  const isValid = await provider.verifySignature(payload, signature, secret);
  if (!isValid) {
    console.warn(`Invalid webhook signature from ${providerName}`);
    return c.json({ error: "Invalid signature" }, 401);
  }

  // Parse the event
  const event = provider.parseEvent(payload);

  // Create database connection
  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  // Generate event ID
  const eventId = `whe_${crypto.randomUUID().replace(/-/g, "")}`;

  // Idempotency: insert collapses on the unique (provider, externalId) index.
  // If a concurrent delivery already inserted the same external event, the
  // ON CONFLICT DO NOTHING returns no row and we short-circuit before
  // enqueueing — handlers run exactly once per externalId.
  // Events with NULL externalId are not subject to dedup (SQLite treats
  // NULL as distinct in unique indexes).
  const [inserted] = await db
    .insert(webhookEvents)
    .values({
      id: eventId,
      provider: providerName,
      eventType: event.type,
      externalId: event.externalId,
      payload,
      status: "received",
    })
    .onConflictDoNothing({
      target: [webhookEvents.provider, webhookEvents.externalId],
    })
    .returning({ id: webhookEvents.id });

  if (!inserted) {
    return c.json({ received: true, duplicate: true });
  }

  // Queue for processing
  const message: InboundWebhookMessage = {
    type: "inbound",
    eventId,
    provider: providerName,
    eventType: event.type,
    payload,
  };

  await c.env.WEBHOOKS_QUEUE.send(message);

  return c.json({ received: true, eventId });
});

/**
 * GET /webhooks/v1/inbound/events
 *
 * List inbound webhook events (admin only)
 */
app.get("/inbound/events", async (c) => {
  const ctx = c.get("ctx");

  if (ctx.userRole !== "admin") {
    return c.json({ error: "Admin access required" }, 403);
  }

  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  const url = new URL(c.req.url);
  const limit = Math.min(parseInt(url.searchParams.get("limit") || "50"), 100);
  const offset = parseInt(url.searchParams.get("offset") || "0");
  const provider = url.searchParams.get("provider");
  const status = url.searchParams.get("status");

  let query = db.select().from(webhookEvents);

  const conditions = [];
  if (provider) {
    conditions.push(eq(webhookEvents.provider, provider));
  }
  if (status) {
    conditions.push(eq(webhookEvents.status, status));
  }

  if (conditions.length > 0) {
    query = query.where(and(...conditions)) as typeof query;
  }

  const events = await query
    .orderBy(desc(webhookEvents.createdAt))
    .limit(limit)
    .offset(offset);

  return c.json({
    data: events,
    pagination: { limit, offset, count: events.length },
  });
});

/**
 * POST /webhooks/v1/inbound/events/:id/retry
 *
 * Retry a failed webhook event (admin only)
 */
app.post("/inbound/events/:id/retry", async (c) => {
  const ctx = c.get("ctx");

  if (ctx.userRole !== "admin") {
    return c.json({ error: "Admin access required" }, 403);
  }

  const eventId = c.req.param("id");
  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  const [event] = await db
    .select()
    .from(webhookEvents)
    .where(eq(webhookEvents.id, eventId))
    .limit(1);

  if (!event) {
    return c.json({ error: "Event not found" }, 404);
  }

  await db
    .update(webhookEvents)
    .set({
      status: "received",
      error: null,
      attempts: 0,
    })
    .where(eq(webhookEvents.id, eventId));

  const message: InboundWebhookMessage = {
    type: "inbound",
    eventId: event.id,
    provider: event.provider,
    eventType: event.eventType,
    payload: event.payload,
  };

  await c.env.WEBHOOKS_QUEUE.send(message);

  return c.json({ success: true, eventId });
});

