/**
 * GET /webhooks/v1/events
 *
 * Get available event types for subscription
 */
app.get("/events", async (c) => {
  return c.json({ events: getAvailableEventTypes() });
});

/**
 * GET /webhooks/v1/endpoints
 *
 * List webhook endpoints for the current user/org
 */
app.get("/endpoints", async (c) => {
  const ctx = c.get("ctx");

  if (!ctx.userId) {
    return c.json({ error: "Not authenticated" }, 401);
  }

  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  const url = new URL(c.req.url);
  const organizationId = url.searchParams.get("organizationId");

  // Build query conditions
  const conditions = [];
  if (organizationId) {
    const check = await requireOrgMember(c, organizationId, WEBHOOK_ADMIN_ROLES);
    if (!check.ok) return check.response;
    conditions.push(eq(webhookEndpoints.organizationId, organizationId));
  } else {
    conditions.push(eq(webhookEndpoints.userId, ctx.userId));
  }

  const endpoints = await db
    .select({
      id: webhookEndpoints.id,
      name: webhookEndpoints.name,
      url: webhookEndpoints.url,
      events: webhookEndpoints.events,
      enabled: webhookEndpoints.enabled,
      createdAt: webhookEndpoints.createdAt,
      updatedAt: webhookEndpoints.updatedAt,
    })
    .from(webhookEndpoints)
    .where(and(...conditions))
    .orderBy(desc(webhookEndpoints.createdAt));

  // Parse events JSON
  const data = endpoints.map(ep => ({
    ...ep,
    events: JSON.parse(ep.events),
  }));

  return c.json({ data });
});

/**
 * POST /webhooks/v1/endpoints
 *
 * Register a new webhook endpoint
 */
app.post("/endpoints", async (c) => {
  const ctx = c.get("ctx");

  if (!ctx.userId) {
    return c.json({ error: "Not authenticated" }, 401);
  }

  const parsedBody = await parseJsonWithSchema(c.req.raw, endpointCreateSchema);
  if (!parsedBody.ok) {
    return c.json(parsedBody, 400);
  }
  const { url, events, name, organizationId } = parsedBody.data;

  // Validate URL (syntax + anti-SSRF)
  if (!isAllowedWebhookUrl(url)) {
    return c.json({ error: "Invalid or disallowed URL" }, 400);
  }

  if (organizationId) {
    const check = await requireOrgMember(c, organizationId, WEBHOOK_ADMIN_ROLES);
    if (!check.ok) return check.response;
  }

  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  const id = `wep_${crypto.randomUUID().replace(/-/g, "")}`;
  const secret = generateWebhookSecret();
  const now = new Date();

  await db.insert(webhookEndpoints).values({
    id,
    organizationId: organizationId || null,
    userId: organizationId ? null : ctx.userId,
    name: name || null,
    url,
    secret,
    events: JSON.stringify(events),
    enabled: true,
    createdAt: now,
  });

  return c.json({
    id,
    name,
    url,
    events,
    enabled: true,
    secret, // Only returned on creation
    createdAt: now,
  }, 201);
});

/**
 * GET /webhooks/v1/endpoints/:id
 *
 * Get endpoint details (secret is partially masked)
 */
app.get("/endpoints/:id", async (c) => {
  const ctx = c.get("ctx");

  if (!ctx.userId) {
    return c.json({ error: "Not authenticated" }, 401);
  }

  const id = c.req.param("id");
  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  const [endpoint] = await db
    .select()
    .from(webhookEndpoints)
    .where(eq(webhookEndpoints.id, id))
    .limit(1);

  if (!endpoint) {
    return c.json({ error: "Endpoint not found" }, 404);
  }

  const accessError = await assertEndpointAccess(c, endpoint);
  if (accessError) return accessError;

  // Mask secret (show first 10 chars)
  const maskedSecret = endpoint.secret.slice(0, 10) + "...";

  return c.json({
    ...endpoint,
    events: JSON.parse(endpoint.events),
    secret: maskedSecret,
  });
});

/**
 * PATCH /webhooks/v1/endpoints/:id
 *
 * Update endpoint
 */
app.patch("/endpoints/:id", async (c) => {
  const ctx = c.get("ctx");

  if (!ctx.userId) {
    return c.json({ error: "Not authenticated" }, 401);
  }

  const id = c.req.param("id");
  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  const [endpoint] = await db
    .select()
    .from(webhookEndpoints)
    .where(eq(webhookEndpoints.id, id))
    .limit(1);

  if (!endpoint) {
    return c.json({ error: "Endpoint not found" }, 404);
  }

  const accessError = await assertEndpointAccess(c, endpoint);
  if (accessError) return accessError;

  const parsedBody = await parseJsonWithSchema(c.req.raw, endpointPatchSchema);
  if (!parsedBody.ok) {
    return c.json(parsedBody, 400);
  }
  const body = parsedBody.data;
  const updates: Record<string, any> = { updatedAt: new Date() };

  if (body.url !== undefined) {
    if (!isAllowedWebhookUrl(body.url)) {
      return c.json({ error: "Invalid or disallowed URL" }, 400);
    }
    updates.url = body.url;
  }

  if (body.events !== undefined) {
    updates.events = JSON.stringify(body.events);
  }

  if (body.name !== undefined) {
    updates.name = body.name;
  }

  if (body.enabled !== undefined) {
    updates.enabled = body.enabled;
  }

  await db
    .update(webhookEndpoints)
    .set(updates)
    .where(eq(webhookEndpoints.id, id));

  const [updated] = await db
    .select()
    .from(webhookEndpoints)
    .where(eq(webhookEndpoints.id, id))
    .limit(1);

  return c.json({
    ...updated,
    events: JSON.parse(updated!.events),
    secret: updated!.secret.slice(0, 10) + "...",
  });
});

/**
 * DELETE /webhooks/v1/endpoints/:id
 *
 * Delete endpoint
 */
app.delete("/endpoints/:id", async (c) => {
  const ctx = c.get("ctx");

  if (!ctx.userId) {
    return c.json({ error: "Not authenticated" }, 401);
  }

  const id = c.req.param("id");
  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  const [endpoint] = await db
    .select()
    .from(webhookEndpoints)
    .where(eq(webhookEndpoints.id, id))
    .limit(1);

  if (!endpoint) {
    return c.json({ error: "Endpoint not found" }, 404);
  }

  const accessError = await assertEndpointAccess(c, endpoint);
  if (accessError) return accessError;

  await db.delete(webhookEndpoints).where(eq(webhookEndpoints.id, id));

  return c.json({ success: true });
});

/**
 * GET /webhooks/v1/endpoints/:id/deliveries
 *
 * List delivery attempts for an endpoint
 */
app.get("/endpoints/:id/deliveries", async (c) => {
  const ctx = c.get("ctx");

  if (!ctx.userId) {
    return c.json({ error: "Not authenticated" }, 401);
  }

  const id = c.req.param("id");
  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  // Check endpoint ownership
  const [endpoint] = await db
    .select()
    .from(webhookEndpoints)
    .where(eq(webhookEndpoints.id, id))
    .limit(1);

  if (!endpoint) {
    return c.json({ error: "Endpoint not found" }, 404);
  }

  const accessError = await assertEndpointAccess(c, endpoint);
  if (accessError) return accessError;

  const url = new URL(c.req.url);
  const limit = Math.min(parseInt(url.searchParams.get("limit") || "50"), 100);
  const offset = parseInt(url.searchParams.get("offset") || "0");

  const deliveries = await db
    .select()
    .from(webhookDeliveries)
    .where(eq(webhookDeliveries.endpointId, id))
    .orderBy(desc(webhookDeliveries.createdAt))
    .limit(limit)
    .offset(offset);

  return c.json({
    data: deliveries,
    pagination: { limit, offset, count: deliveries.length },
  });
});

/**
 * POST /webhooks/v1/endpoints/:id/test
 *
 * Send a test event to the endpoint
 */
app.post("/endpoints/:id/test", async (c) => {
  const ctx = c.get("ctx");

  if (!ctx.userId) {
    return c.json({ error: "Not authenticated" }, 401);
  }

  const id = c.req.param("id");
  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  const [endpoint] = await db
    .select()
    .from(webhookEndpoints)
    .where(eq(webhookEndpoints.id, id))
    .limit(1);

  if (!endpoint) {
    return c.json({ error: "Endpoint not found" }, 404);
  }

  const accessError = await assertEndpointAccess(c, endpoint);
  if (accessError) return accessError;

  if (!isAllowedWebhookUrl(endpoint.url)) {
    return c.json({ error: "Invalid or disallowed URL" }, 400);
  }

  // Create test payload
  const testPayload = JSON.stringify({
    type: "webhook.test",
    data: {
      message: "This is a test webhook",
      timestamp: new Date().toISOString(),
    },
    createdAt: new Date().toISOString(),
  });

  // Sign and send immediately (not queued)
  const signature = await signPayload(testPayload, endpoint.secret);

  try {
    const response = await fetch(endpoint.url, {
      method: "POST",
      // SSRF: refuse to follow redirects so a registered HTTPS endpoint can't
      // 302 the signed test payload into an internal address. We mirror the
      // queued delivery path's behavior (see below) and surface a 3xx as a
      // failed test rather than transparently following it.
      redirect: "manual",
      headers: {
        "Content-Type": "application/json",
        "X-Webhook-Signature": signature,
        "X-Webhook-Event": "webhook.test",
      },
      body: testPayload,
    });

    if (response.status >= 300 && response.status < 400) {
      return c.json({
        success: false,
        status: response.status,
        statusText: response.statusText,
        error: "Endpoint responded with a redirect; webhooks won't follow redirects to internal addresses.",
      });
    }

    return c.json({
      success: response.ok,
      status: response.status,
      statusText: response.statusText,
    });
  } catch (error) {
    return c.json({
      success: false,
      error: error instanceof Error ? error.message : "Request failed",
    });
  }
});

/**
 * POST /webhooks/v1/endpoints/:id/rotate-secret
 *
 * Generate a new secret for the endpoint
 */
app.post("/endpoints/:id/rotate-secret", async (c) => {
  const ctx = c.get("ctx");

  if (!ctx.userId) {
    return c.json({ error: "Not authenticated" }, 401);
  }

  const id = c.req.param("id");
  const db = createWebhooksDb(c.env.WEBHOOKS_DB);

  const [endpoint] = await db
    .select()
    .from(webhookEndpoints)
    .where(eq(webhookEndpoints.id, id))
    .limit(1);

  if (!endpoint) {
    return c.json({ error: "Endpoint not found" }, 404);
  }

  const accessError = await assertEndpointAccess(c, endpoint);
  if (accessError) return accessError;

  const newSecret = generateWebhookSecret();

  await db
    .update(webhookEndpoints)
    .set({
      secret: newSecret,
      updatedAt: new Date(),
    })
    .where(eq(webhookEndpoints.id, id));

  return c.json({ secret: newSecret });
});

export default app;

// ═══════════════════════════════════════════════════════════════════
// Queue Consumer Handler
// ═══════════════════════════════════════════════════════════════════

/**
 * Process webhook queue messages
 * Called by the queue consumer in index.ts
 */
export async function handleWebhookMessage(
  message: WebhookMessage,
  env: CloudflareBindings
): Promise<void> {
  const db = createWebhooksDb(env.WEBHOOKS_DB);

  if (message.type === "inbound") {
    await handleInboundMessage(message, env, db);
  } else if (message.type === "outbound") {
    await handleOutboundMessage(message, env, db);
  }
}

async function handleInboundMessage(
  message: InboundWebhookMessage,
  env: CloudflareBindings,
  db: ReturnType<typeof createWebhooksDb>
): Promise<void> {
  const { eventId, provider, eventType, payload } = message;

  await db
    .update(webhookEvents)
    .set({ status: "processing" })
    .where(eq(webhookEvents.id, eventId));

  try {
    const data = JSON.parse(payload);
    const eventData = data.data?.object || data.data || data;

    await dispatchEvent(provider, eventType, eventData, env);

    await db
      .update(webhookEvents)
      .set({
        status: "processed",
        processedAt: new Date(),
      })
      .where(eq(webhookEvents.id, eventId));
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);

    const [event] = await db
      .select({ attempts: webhookEvents.attempts })
      .from(webhookEvents)
      .where(eq(webhookEvents.id, eventId))
      .limit(1);

    await db
      .update(webhookEvents)
      .set({
        status: "failed",
        error: errorMessage,
        attempts: (event?.attempts || 0) + 1,
      })
      .where(eq(webhookEvents.id, eventId));

    throw error;
  }
}

async function handleOutboundMessage(
  message: OutboundWebhookMessage,
  env: CloudflareBindings,
  db: ReturnType<typeof createWebhooksDb>
): Promise<void> {
  const { deliveryId, endpointId, eventType, payload } = message;

  // Get endpoint details
  const [endpoint] = await db
    .select()
    .from(webhookEndpoints)
    .where(eq(webhookEndpoints.id, endpointId))
    .limit(1);

  if (!endpoint) {
    // Endpoint deleted, mark delivery as failed
    await db
      .update(webhookDeliveries)
      .set({
        status: "failed",
        responseBody: "Endpoint not found",
        lastAttemptAt: new Date(),
      })
      .where(eq(webhookDeliveries.id, deliveryId));
    return;
  }

  if (!endpoint.enabled) {
    // Endpoint disabled, mark as failed
    await db
      .update(webhookDeliveries)
      .set({
        status: "failed",
        responseBody: "Endpoint disabled",
        lastAttemptAt: new Date(),
      })
      .where(eq(webhookDeliveries.id, deliveryId));
    return;
  }

  if (!isAllowedWebhookUrl(endpoint.url)) {
    await db
      .update(webhookDeliveries)
      .set({
        status: "failed",
        responseBody: "Endpoint URL is disallowed",
        lastAttemptAt: new Date(),
      })
      .where(eq(webhookDeliveries.id, deliveryId));
    return;
  }

  // Sign payload
  const signature = await signPayload(payload, endpoint.secret);

  // Get current attempts
  const [delivery] = await db
    .select({ attempts: webhookDeliveries.attempts })
    .from(webhookDeliveries)
    .where(eq(webhookDeliveries.id, deliveryId))
    .limit(1);

  const attempts = (delivery?.attempts || 0) + 1;
  const now = new Date();

  try {
    const response = await fetch(endpoint.url, {
      method: "POST",
      // SSRF: refuse to follow redirects so a public endpoint can't bounce
      // a signed payload into an internal address. 3xx is treated as a
      // terminal delivery failure (no retry) below.
      redirect: "manual",
      headers: {
        "Content-Type": "application/json",
        "X-Webhook-Signature": signature,
        "X-Webhook-Event": eventType,
        "X-Webhook-Delivery": deliveryId,
      },
      body: payload,
    });

    if (response.status >= 300 && response.status < 400) {
      const location = response.headers.get("location") || "<unknown>";
      await db
        .update(webhookDeliveries)
        .set({
          status: "failed",
          attempts,
          lastAttemptAt: now,
          nextRetryAt: null,
          responseStatus: response.status,
          responseBody: `Refused to follow redirect to ${location}`.slice(0, 1000),
        })
        .where(eq(webhookDeliveries.id, deliveryId));
      return;
    }

    const responseBody = await response.text().catch(() => "");

    if (response.ok) {
      // Success
      await db
        .update(webhookDeliveries)
        .set({
          status: "delivered",
          attempts,
          lastAttemptAt: now,
          responseStatus: response.status,
          responseBody: responseBody.slice(0, 1000), // Truncate
        })
        .where(eq(webhookDeliveries.id, deliveryId));
    } else {
      // HTTP error - calculate next retry with exponential backoff
      const nextRetryAt = new Date(now.getTime() + Math.min(Math.pow(2, attempts) * 1000, 3600000)); // Max 1 hour

      await db
        .update(webhookDeliveries)
        .set({
          status: "pending", // Keep pending for retry
          attempts,
          lastAttemptAt: now,
          nextRetryAt,
          responseStatus: response.status,
          responseBody: responseBody.slice(0, 1000),
        })
        .where(eq(webhookDeliveries.id, deliveryId));

      // Throw to trigger queue retry
      throw new Error(`HTTP ${response.status}: ${response.statusText}`);
    }
  } catch (error) {
    // Network error
    const errorMessage = error instanceof Error ? error.message : String(error);
    const nextRetryAt = new Date(now.getTime() + Math.min(Math.pow(2, attempts) * 1000, 3600000));

    await db
      .update(webhookDeliveries)
      .set({
        status: attempts >= 3 ? "failed" : "pending",
        attempts,
        lastAttemptAt: now,
        nextRetryAt: attempts >= 3 ? null : nextRetryAt,
        responseBody: errorMessage.slice(0, 1000),
      })
      .where(eq(webhookDeliveries.id, deliveryId));

    if (attempts < 3) {
      throw error; // Trigger retry
    }
    // Max retries reached, don't throw
  }
}

